import React, { createContext, useContext, useState, useEffect } from 'react';
import { isAddress, getAddress } from 'ethers';
import { uploadMessageToIPFS, getMessageFromIPFS } from '../utils/ipfs';
import { getContract, addMessageToRoom, getRoomMessages } from '../utils/contract';
import { listenToMessageAdded } from '../utils/events';

const ChatContext = createContext();

export const useChat = () => {
  const context = useContext(ChatContext);
  if (!context) {
    throw new Error('useChat must be used within a ChatProvider');
  }
  return context;
};

export const ChatProvider = ({ children }) => {
  const [chatRooms, setChatRooms] = useState([
    {
      id: '1',
      name: 'DeChat Genesis Holders',
      description: 'Exclusive chat for DeChat Genesis NFT holders',
      requiredNFT: 'DeChat Genesis',
      memberCount: 127,
      hasAccess: true,
      isActive: true
    },
    {
      id: '2',
      name: 'CryptoPunks Lounge',
      description: 'Chat room for CryptoPunks collectors',
      requiredNFT: 'CryptoPunks',
      memberCount: 89,
      hasAccess: true,
      isActive: false
    },
    {
      id: '3',
      name: 'BAYC Exclusive',
      description: 'Bored Ape Yacht Club members only',
      requiredNFT: 'Bored Ape Yacht Club',
      memberCount: 234,
      hasAccess: false,
      isActive: false
    }
  ]);

  const [messages, setMessages] = useState({
    '1': [],
    '2': []
  });

  const [chats, setChats] = useState([]);
  const [activeChatId, setActiveChatId] = useState(null);
  const [connectedWallet, setConnectedWallet] = useState(null);
  const [loadedHashes, setLoadedHashes] = useState(new Set());
  const [isLoading, setIsLoading] = useState(false);

  // Polling system - reads from blockchain OR localStorage
  useEffect(() => {
    if (!activeChatId || !connectedWallet) return;

    const fetchMessages = async () => {
      try {
        console.log('🔄 Polling for messages in room:', activeChatId);
        
        let hashes = [];
        
        // Try blockchain first
        try {
          const contract = await getContract();
          
          if (contract && typeof contract.getRoomMessages === 'function') {
            hashes = await getRoomMessages(contract, activeChatId);
            console.log('📥 Received hashes from blockchain:', hashes);
          }
        } catch (contractError) {
          console.log('⚠️ Blockchain not available, using localStorage');
        }
        
        // Fallback to localStorage if blockchain not available
        if (hashes.length === 0) {
          const storageKey = `chat_hashes_${activeChatId}`;
          const storedHashes = JSON.parse(localStorage.getItem(storageKey) || '[]');
          hashes = storedHashes;
          console.log('📥 Received hashes from localStorage:', hashes);
        }

        // Download messages from IPFS
        for (const hash of hashes) {
          if (loadedHashes.has(hash)) {
            continue;
          }

          try {
            console.log('📦 Downloading message from IPFS:', hash);
            const messageData = await getMessageFromIPFS(hash);
            
            setLoadedHashes(prev => new Set([...prev, hash]));
            
            setChats(prev =>
              prev.map(chat => {
                if (chat.id === activeChatId) {
                  const exists = chat.messages.some(msg => msg.ipfsHash === hash);
                  if (!exists) {
                    console.log('✅ New message added:', messageData);
                    return {
                      ...chat,
                      messages: [...chat.messages, { ...messageData, ipfsHash: hash }]
                    };
                  }
                }
                return chat;
              })
            );
          } catch (err) {
            console.error('Failed to download message from IPFS:', hash, err);
          }
        }
      } catch (err) {
        console.error('Polling error:', err);
      }
    };

    fetchMessages(); // Initial load
    const interval = setInterval(fetchMessages, 5000); // Poll every 5 seconds

    return () => clearInterval(interval);
  }, [activeChatId, connectedWallet, loadedHashes]);

  // Listen to real-time events (if contract deployed)
  useEffect(() => {
    if (!activeChatId) return;

    const setupEventListener = async () => {
      try {
        await listenToMessageAdded(activeChatId, async (event) => {
          console.log('🔔 Real-time message event:', event);
          
          // Download new message from IPFS
          if (!loadedHashes.has(event.ipfsHash)) {
            try {
              const messageData = await getMessageFromIPFS(event.ipfsHash);
              
              setLoadedHashes(prev => new Set([...prev, event.ipfsHash]));
              
              setChats(prev =>
                prev.map(chat => {
                  if (chat.id === activeChatId) {
                    return {
                      ...chat,
                      messages: [...chat.messages, { ...messageData, ipfsHash: event.ipfsHash }]
                    };
                  }
                  return chat;
                })
              );
            } catch (err) {
              console.error('Failed to download message from event:', err);
            }
          }
        });
      } catch (err) {
        console.log('⚠️ Event listeners not available:', err.message);
      }
    };

    setupEventListener();
  }, [activeChatId, loadedHashes]);

  const setWallet = (walletAddress) => {
    setConnectedWallet(walletAddress);
  };

  const createPrivateChat = (targetWalletAddress, currentAccount) => {
    if (!currentAccount) {
      return { success: false, error: 'Wallet not connected' };
    }

    if (!targetWalletAddress || !targetWalletAddress.trim()) {
      return { success: false, error: 'Please enter a wallet address' };
    }

    const trimmedAddress = targetWalletAddress.trim();

    if (!isAddress(trimmedAddress)) {
      return { success: false, error: 'Invalid Ethereum address' };
    }

    const normalizedTarget = getAddress(trimmedAddress);
    const normalizedCurrent = getAddress(currentAccount);

    if (normalizedTarget === normalizedCurrent) {
      return { success: false, error: 'You cannot chat with yourself' };
    }

    const chatId = [normalizedCurrent.toLowerCase(), normalizedTarget.toLowerCase()]
      .sort()
      .join('_');

    console.log('🔑 Generated chatId:', chatId);
    console.log('👥 Participants:', [normalizedCurrent, normalizedTarget]);

    const existingChat = chats.find(chat => chat.id === chatId);

    if (existingChat) {
      setActiveChatId(chatId);
      console.log('📂 Existing chat activated:', chatId);
      return { success: true, chatId, isNew: false };
    }

    const newChat = {
      id: chatId,
      participants: [normalizedCurrent, normalizedTarget],
      messages: []
    };

    setChats(prev => [...prev, newChat]);
    setActiveChatId(chatId);
    console.log('✨ New chat created:', chatId);

    return { success: true, chatId, isNew: true };
  };

  const sendPrivateMessage = async (text) => {
    if (!activeChatId || !connectedWallet) {
      console.error('❌ Cannot send message - no active chat or wallet');
      return;
    }

    if (!text.trim()) return;

    const activeChat = chats.find(chat => chat.id === activeChatId);
    if (!activeChat) return;

    const receiver = activeChat.participants.find(
      p => p.toLowerCase() !== connectedWallet.toLowerCase()
    );

    setIsLoading(true);

    try {
      const messageId = `msg_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`;
      
      const message = {
        id: messageId,
        sender: connectedWallet,
        receiver: receiver,
        content: text,
        timestamp: new Date().toISOString()
      };

      console.log('📤 Uploading message to IPFS...');
      
      // 1. Upload to IPFS
      const ipfsHash = await uploadMessageToIPFS(message);
      console.log('✅ Message uploaded to IPFS:', ipfsHash);

      // 2. Store hash in localStorage (temporary sync mechanism)
      const storageKey = `chat_hashes_${activeChatId}`;
      const existingHashes = JSON.parse(localStorage.getItem(storageKey) || '[]');
      
      // Prevent duplicates
      if (!existingHashes.includes(ipfsHash)) {
        existingHashes.push(ipfsHash);
        localStorage.setItem(storageKey, JSON.stringify(existingHashes));
        console.log('✅ Hash saved to localStorage for cross-browser sync');
      }

      // 3. Try to add hash to smart contract (if deployed)
      try {
        const contract = await getContract();
        
        if (contract && typeof contract.addMessage === 'function') {
          await addMessageToRoom(contract, activeChatId, ipfsHash);
          console.log('✅ Hash added to blockchain');
        } else {
          console.warn('⚠️ Smart contract not deployed. Using localStorage sync.');
        }
      } catch (contractError) {
        console.warn('⚠️ Blockchain not available. Using localStorage sync.');
      }

      // 4. Optimistic UI update
      setLoadedHashes(prev => new Set([...prev, ipfsHash]));
      
      setChats(prev =>
        prev.map(chat =>
          chat.id === activeChatId
            ? { ...chat, messages: [...chat.messages, { ...message, ipfsHash }] }
            : chat
        )
      );
      
      console.log('✅ Message sent successfully');
    } catch (err) {
      console.error('❌ Send message error:', err);
      alert('Failed to send message: ' + err.message);
    } finally {
      setIsLoading(false);
    }
  };

  const deletePrivateMessage = (messageId, deleteType) => {
    if (!activeChatId) return;

    setChats(prev =>
      prev.map(chat => {
        if (chat.id === activeChatId) {
          return {
            ...chat,
            messages: chat.messages.map(msg => {
              if (msg.id === messageId) {
                if (deleteType === 'forMe') {
                  return { ...msg, deletedForMe: true };
                } else if (deleteType === 'forEveryone') {
                  return {
                    ...msg,
                    deletedForEveryone: true,
                    content: 'This message was deleted'
                  };
                }
              }
              return msg;
            })
          };
        }
        return chat;
      })
    );
  };

  const getActiveChat = () => {
    return chats.find(chat => chat.id === activeChatId);
  };

  const privateChats = chats;
  const privateMessages = chats.reduce((acc, chat) => {
    acc[chat.id] = chat.messages;
    return acc;
  }, {});

  const [mintedMessages, setMintedMessages] = useState([]);

  const sendMessage = (roomId, content) => {
    const newMessage = {
      id: Date.now().toString(),
      sender: connectedWallet || '0x742d35Cc6634C0532925a3b8D0C9C0E3C5d5c8E9',
      content,
      timestamp: new Date(),
      ipfsHash: `QmMock${Date.now()}...`,
      canMint: true
    };

    setMessages(prev => ({
      ...prev,
      [roomId]: [...(prev[roomId] || []), newMessage]
    }));
  };

  const mintMessageAsNFT = async (messageId, roomId) => {
    console.log(`Minting message ${messageId} from room ${roomId} as NFT...`);
    await new Promise(resolve => setTimeout(resolve, 2000));

    const result = {
      success: true,
      transactionHash: `0xmock${Date.now()}`,
      tokenId: Math.floor(Math.random() * 10000)
    };

    const roomMessages = messages[roomId] || [];
    const message = roomMessages.find(msg => msg.id === messageId);
    const room = chatRooms.find(r => r.id === roomId);

    if (message && room) {
      const newMintedMessage = {
        id: messageId,
        content: message.content,
        tokenId: result.tokenId.toString(),
        mintDate: new Date(),
        room: room.name,
        transactionHash: result.transactionHash
      };

      setMintedMessages(prev => [...prev, newMintedMessage]);
    }

    return result;
  };

  const createRoom = (roomData) => {
    const newRoom = {
      id: Date.now().toString(),
      name: roomData.name,
      description: roomData.description,
      type: roomData.type || 'public',
      requiredNFT: roomData.requiredNFT,
      nftContractAddress: roomData.nftContractAddress || null,
      nftOption: roomData.nftOption || null,
      existingNFTId: roomData.existingNFTId || null,
      memberCount: 1,
      hasAccess: true,
      isActive: true,
      createdBy: roomData.createdBy,
      createdAt: new Date(),
      mintPrice: roomData.mintPrice || null,
      maxSupply: roomData.maxSupply || null
    };

    setChatRooms(prev => [...prev, newRoom]);

    setMessages(prev => ({
      ...prev,
      [newRoom.id]: []
    }));

    return newRoom;
  };

  const deleteRoom = (roomId) => {
    setChatRooms(prev => prev.filter(room => room.id !== roomId));

    setMessages(prev => {
      const newMessages = { ...prev };
      delete newMessages[roomId];
      return newMessages;
    });
  };

  const removeMintedMessage = (messageId) => {
    setMintedMessages(prev => prev.filter(msg => msg.id !== messageId));
  };

  const leaveRoom = (roomId) => {
    setChatRooms(prev => prev.map(room => {
      if (room.id === roomId) {
        return {
          ...room,
          hasAccess: false,
          memberCount: Math.max(0, room.memberCount - 1)
        };
      }
      return room;
    }));
  };

  const value = {
    chatRooms,
    messages,
    privateChats,
    privateMessages,
    chats,
    activeChatId,
    mintedMessages,
    isLoading,
    sendMessage,
    sendPrivateMessage,
    deletePrivateMessage,
    createPrivateChat,
    getActiveChat,
    mintMessageAsNFT,
    createRoom,
    deleteRoom,
    removeMintedMessage,
    leaveRoom,
    setWallet
  };

  return (
    <ChatContext.Provider value={value}>
      {children}
    </ChatContext.Provider>
  );
};
